SELECT id, title, content, cover, create_time, category, view_count, like_count
FROM content
WHERE biz_type = 'culture'

    AND category = #{category}

ORDER BY create_time DESC
LIMIT #{offset}, #{size}

mapper.update:
UPDATE content
SET view_count = view_count + 1
WHERE id = #{id}

UPDATE content
SET like_count = like_count + 1
WHERE id = #{id}
